module RefModule (  
    input wire [7:0] data,  
    input wire we,  
    input wire re,  
    output reg [7:0] q  
);  
    reg [7:0] obf_memory;  

    always @(posedge we) begin  
        obf_memory <= data;  
    end  

    always @(posedge re) begin  
        q <= obf_memory;  
    end  
endmodule
